function render(node) {
  if (node == null) return document.createTextNode('');
  if (typeof node === 'string' || typeof node === 'number') return document.createTextNode(String(node));
  const el = document.createElement(node.type);
  const props = node.props || {};
  for (const [k, v] of Object.entries(props)) {
    if (v == null) continue;
    el.setAttribute(k === 'className' ? 'class' : k, String(v));
  }
  const children = node.children;
  if (Array.isArray(children)) children.forEach((c) => el.appendChild(render(c)));
  else if (children != null) el.appendChild(render(children));
  return el;
}

timerRender.render = render;

export default timerRender;
